const items = $input.all();
const result = [];

// We use a standard for-loop to handle async/await properly
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const form = item.json;

  const category = form['Product Category'] || 'Area Rug';
  const focus = form['Focus Area'] || '';

  // Helper function to wait for the data to actually load
  const getFileContent = async (fieldName) => {
    try {
      if (item.binary && item.binary[fieldName]) {
        // 'await' tells the code to stop and wait for the file to be read
        const buffer = await this.helpers.getBinaryDataBuffer(i, fieldName);
        return buffer.toString('utf8');
      }
    } catch (e) {
      console.error(`Error reading ${fieldName}:`, e);
    }
    return null;
  };

  // We must 'await' these calls now
  const p2Raw = await getFileContent('P2_Market_Analysis_Report');
  const p3Raw = await getFileContent('P3_Competitor_Analysis_Report');

  const stripHtml = (html) => {
    if (!html || html.length < 10) return 'MISSING_DATA';
    return html
      .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
      .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
      .replace(/<[^>]+>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
  };

  result.push({
    json: {
      category,
      focus,
      p2_content: stripHtml(p2Raw).slice(0, 15000),
      p3_content: stripHtml(p3Raw).slice(0, 15000)
    }
  });
}

return result;

