let metricsHtml = metrics.map(m => `
  <div class="insight-card">
    <div class="number">${esc(m.value)}</div>
    <div class="label">${esc(m.label)}</div>
  </div>
`).join('');

// 2. Data Foundation (Original Grid Style)
const df = c.data_foundation || {};
let p2List = (df.p2_insights || []).map(i => `<li>${esc(i)}</li>`).join('');
let p3List = (df.p3_insights || []).map(i => `<li>${esc(i)}</li>`).join('');

// 3. Narrative SEO Content (New Section, Original Styling)
const seoNarrative = c.product_narrative_150 || '';

// 4. Video Concepts (Wayfair Aesthetic, Original Card Style)
const vids = c.aesthetic_video_concepts || [];
let vidsHtml = vids.map(v => `
  <div class="content-card">
    <div class="content-card-header">
      <div class="type">Aesthetic Video</div>
      <h4>${esc(v.concept_name)}</h4>
    </div>
    <div class="content-card-body">
      <p><strong>Soundscape:</strong> <i>${esc(v.soundscape)}</i></p>
