      <p style="font-size:0.9em; color:#666;">${esc(v.visual_beats)}</p>
      <div class="manifesto-box" style="margin-top:15px; border-top:1px solid #eee; padding-top:10px;">
        <strong>Manifesto:</strong> <span style="color:#7B2D8E; font-weight:600;">"${esc(v.manifesto_caption)}"</span>
      </div>
    </div>
  </div>
`).join('');

// 5. Editorial Blueprints (Formerly Content Ideas)
const blueprints = c.blog_blueprints || [];
let blueprintsHtml = blueprints.map(b => {
  const structure = (b.structure || []).map(s => `<li>${esc(s)}</li>`).join('');
  return `
  <div class="campaign-card">
    <div class="vibe-tag" style="color:#B4975A; font-size:0.75em; text-transform:uppercase; font-weight:bold;">Editorial Guide</div>
