         <p>${esc(b.wayfair_edge)}</p>
       </div>
    </div>
  </div>`;
}).join('');

// 6. Strategic Emails (Original Email Style)
const emails = c.email_sequences || [];
let emailsHtml = emails.map(e => `
  <div class="email-subject">
    <span class="icon">📧</span>
    <span class="subject-text"><strong>${esc(e.stage)}:</strong> ${esc(e.subject)}</span>
    <div style="padding:10px; background:#fff; margin-top:10px; border-radius:4px; font-size:0.9em; color:#555;">${esc(e.body)}</div>
  </div>
`).join('');

// 7. Competitive Angles (Original Style)
const angles = c.competitive_angles || [];
let anglesHtml = angles.map(a => `
  <div class="competitive-angle">
    <h4>${esc(a.title)}</h4>
    <p><strong>Market Gap:</strong> ${esc(a.gap_in_market)}</p>
    <p><strong>Our Edge:</strong> ${esc(a.wayfair_edge)}</p>
  </div>
`).join('');

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Wayfair Brand Strategy | ${esc(category)}</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; line-height: 1.6; color: #333; background: #f8f9fa; }
