return [{json: {html, category, focus}}];

const html = $input.first().json.html;
const cat = $input.first().json.category || 'Area Rug';
const ts = new Date().toISOString().split('T')[0];
const fileName = `Wayfair_${cat.replace(/\s+/g, '_')}_Content_Strategy_${ts}.html`;

return [{
  json: { html, fileName },
  binary: {
    data: {
      data: Buffer.from(html).toString('base64'),
      mimeType: 'text/html',
      fileName: fileName
    }
  }
}];
